import { describe, it, expect } from "vitest";
import { matchesAnyTaskType } from "@/lib/orama-browser";

// Unit coverage for the agent task-type filter predicate extracted from
// agent-selector.tsx. Semantics: empty selection = no filter; otherwise an
// agent matches if it carries ANY selected task type (OR).
describe("matchesAnyTaskType", () => {
  it("empty selection = no filter (always true)", () => {
    expect(matchesAnyTaskType([], [])).toBe(true);
    expect(matchesAnyTaskType(["build"], [])).toBe(true);
    expect(matchesAnyTaskType(["build", "test"], [])).toBe(true);
  });

  it("single selected type that the agent has -> true", () => {
    expect(matchesAnyTaskType(["build", "test"], ["build"])).toBe(true);
  });

  it("single selected type the agent lacks -> false", () => {
    expect(matchesAnyTaskType(["build", "test"], ["deploy"])).toBe(false);
  });

  it("multi-select OR: one of several selected matches -> true", () => {
    expect(
      matchesAnyTaskType(["review"], ["build", "review", "deploy"]),
    ).toBe(true);
  });

  it("multi-select where none match -> false", () => {
    expect(
      matchesAnyTaskType(["document"], ["build", "review", "deploy"]),
    ).toBe(false);
  });

  it("agent with no task types and a non-empty selection -> false", () => {
    expect(matchesAnyTaskType([], ["build"])).toBe(false);
  });
});
